+	}
+
+	g := NewDependencyGraph(w)
+	errs := g.Validate()
+
+	// All dependencies exist, so no missing_dep errors
+	for _, e := range errs {
+		if e.Type == "missing_dep" {
+			t.Errorf("unexpected missing_dep error: %v", e)
+		}
+	}
+}
